select id, title, description, price, type, create_time
from subscription_package
where id = #{id}

select id, title, description, price, type, status, create_time from subscription_package
and status = #{status}
and (title like concat('%', #{keyword}, '%') or description like concat('%', #{keyword}, '%'))
order by id desc limit #{offset}, #{pageSize}

select count(*) from subscription_package
and status = #{status}
and (title like concat('%', #{keyword}, '%') or description like concat('%', #{keyword}, '%'))
